// ============ PARSING & CONSOLIDATION ============
const now = new Date();
const dayAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);

// --- 1. Récupérer les 4 flux ---
const errorsExec = $('Exec en erreur 24h').first().json.data || [];
const successExec = $('Exec réussies 24h').first().json.data || [];
const chasseRows = $('Lire Tableau Chasse').all().map(i => i.json);
const sujetsRows = $('Lire Sujets Ouverts').all().map(i => i.json);

// --- 2. Workflows plantés (filtre 24h) ---
const errors24h = errorsExec.filter(e => new Date(e.startedAt) > dayAgo);

// --- 3. Récurrences exécutées (mode=trigger, filtre 24h) ---
// Mode 'trigger' = scheduled/webhook automatique
const recurrences = successExec.filter(e => 
  new Date(e.startedAt) > dayAgo && 
  (e.mode === 'trigger' || e.mode === 'webhook')
);
// Grouper par workflow
const recByWf = {};
for (const r of recurrences) {
  const wf = r.workflowData?.name || r.workflowId || 'Inconnu';
  recByWf[wf] = (recByWf[wf] || 0) + 1;
}

// --- 4. Sujets à relancer (tableau chasse, statut contient 'relanc' ou 'attente') ---
const aRelancer = chasseRows.filter(r => {
  const s = (r['Statut'] || '').toLowerCase();
  return s.includes('relanc') || s.includes('attente') || s.includes('rappel');
});

// --- 5. Sujets ouverts (conversations Claude non closes) ---
// Convention sheet : sujet | date | lien | deadline | statut
const ouverts = sujetsRows.filter(r => {
  const s = (r['statut'] || r['Statut'] || '').toLowerCase();
  return s !== 'fait' && s !== 'clos' && s !== 'done';
});

// --- 6. Composer HTML ---
const fmtDate = d => new Date(d).toLocaleString('fr-FR', {timeZone:'Europe/Paris', day:'2-digit', month:'2-digit', hour:'2-digit', minute:'2-digit'});

let html = `<!DOCTYPE html><html><head><meta charset="utf-8"><style>
body{font-family:-apple-system,Segoe UI,sans-serif;background:#f7f9fb;color:#1a2332;margin:0;padding:20px;}
.wrap{max-width:680px;margin:0 auto;background:#fff;border-radius:12px;padding:28px;box-shadow:0 2px 8px rgba(0,0,0,0.04);}
h1{color:#0f4c75;font-size:22px;margin:0 0 4px;}
.date{color:#6b7f95;font-size:13px;margin-bottom:24px;}
h2{font-size:15px;margin:24px 0 12px;padding:8px 12px;border-radius:6px;}
h2.err{background:#fde8e8;color:#9b1c1c;}
h2.rel{background:#fef3c7;color:#92400e;}
h2.ouv{background:#dbeafe;color:#1e40af;}
h2.rec{background:#d1fae5;color:#065f46;}
ul{margin:0;padding-left:20px;}
li{margin:6px 0;line-height:1.5;font-size:14px;}
.meta{color:#6b7f95;font-size:12px;}
.empty{color:#6b7f95;font-style:italic;font-size:13px;padding-left:12px;}
a{color:#0f4c75;}
.count{background:#fff;color:#1a2332;padding:2px 8px;border-radius:10px;font-size:12px;margin-left:8px;}
</style></head><body><div class="wrap">`;

html += `<h1>📊 Rapport quotidien</h1><div class="date">${now.toLocaleDateString('fr-FR', {timeZone:'Europe/Paris', weekday:'long', day:'numeric', month:'long'})}</div>`;

// Section 1 : Workflows plantés
html += `<h2 class="err">⚠️ Workflows plantés <span class="count">${errors24h.length}</span></h2>`;
if (errors24h.length === 0) {
  html += `<div class="empty">Aucun plantage. RAS.</div>`;
} else {
  html += `<ul>`;
  for (const e of errors24h.slice(0, 20)) {
    const wfName = e.workflowData?.name || e.workflowId;
    html += `<li><strong>${wfName}</strong> <span class="meta">— ${fmtDate(e.startedAt)}</span><br><span class="meta">Exec ID ${e.id}</span></li>`;
  }
  html += `</ul>`;
}

// Section 2 : Récurrences
html += `<h2 class="rec">🔄 Récurrences exécutées <span class="count">${recurrences.length}</span></h2>`;
const recEntries = Object.entries(recByWf).sort((a,b) => b[1]-a[1]);
if (recEntries.length === 0) {
  html += `<div class="empty">Aucune.</div>`;
} else {
  html += `<ul>`;
  for (const [wf, count] of recEntries) {
    html += `<li><strong>${wf}</strong> <span class="meta">— ${count} exec</span></li>`;
  }
  html += `</ul>`;
}

// Section 3 : Sujets à relancer
html += `<h2 class="rel">📌 Sujets à relancer <span class="count">${aRelancer.length}</span></h2>`;
if (aRelancer.length === 0) {
  html += `<div class="empty">Aucun.</div>`;
} else {
  html += `<ul>`;
  for (const r of aRelancer.slice(0, 25)) {
    const qui = r['Qui'] || r['Entreprise'] || '?';
    const enseigne = r['Enseigne envisagée'] || '';
    const statut = r['Statut'] || '';
    const com = (r['Commentaire'] || '').substring(0, 80);
    html += `<li><strong>${qui}</strong> <span class="meta">${enseigne} · ${statut}</span><br><span class="meta">${com}</span></li>`;
  }
  html += `</ul>`;
}

// Section 4 : Sujets Claude ouverts
html += `<h2 class="ouv">💬 Sujets ouverts (convos Claude) <span class="count">${ouverts.length}</span></h2>`;
if (ouverts.length === 0) {
  html += `<div class="empty">Aucun. Tape "track" en fin de conversation pour ajouter un sujet ici.</div>`;
} else {
  html += `<ul>`;
  for (const r of ouverts) {
    const sujet = r['sujet'] || r['Sujet'] || '?';
    const date = r['date'] || r['Date'] || '';
    const lien = r['lien'] || r['Lien'] || '';
    const deadline = r['deadline'] || r['Deadline'] || '';
    html += `<li><strong>${sujet}</strong>`;
    if (deadline) html += ` <span class="meta">· échéance ${deadline}</span>`;
    html += `<br><span class="meta">${date}</span>`;
    if (lien) html += ` · <a href="${lien}">ouvrir la conversation</a>`;
    html += `</li>`;
  }
  html += `</ul>`;
}

html += `</div></body></html>`;

return [{
  json: {
    to: 'thierry@thierrybismuth.com',
    subject: `📊 Daily ${now.toLocaleDateString('fr-FR', {timeZone:'Europe/Paris', day:'2-digit', month:'2-digit'})} — ${errors24h.length} err · ${aRelancer.length} relances · ${ouverts.length} ouverts`,
    html: html,
    stats: {
      errors: errors24h.length,
      recurrences: recurrences.length,
      relances: aRelancer.length,
      ouverts: ouverts.length
    }
  }
}];
